CREATE TABLE `command_settings` (`id` int AUTO_INCREMENT NOT NULL, `guildId` varchar(64) NOT NULL, `commandName` varchar(64) NOT NULL, `enabled` boolean NOT NULL DEFAULT true, `cooldown` int DEFAULT 0, `requiredRoleId` varchar(64), `allowedChannels` json DEFAULT ('[]'), `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `command_settings_id` PRIMARY KEY(`id`));
ALTER TABLE `users` ADD `discordId` varchar(64);
ALTER TABLE `users` ADD `avatar` text;
ALTER TABLE `users` ADD `accessToken` text;
ALTER TABLE `users` ADD `refreshToken` text

